"use strict";(globalThis.webpackChunkggv_blogs=globalThis.webpackChunkggv_blogs||[]).push([[734],{7102(e,a,i){i.r(a),i.d(a,{assets:()=>g,cloudinaryOriginalBaseUrl:()=>c,cloudinaryThumbnailBaseUrl:()=>p,contentTitle:()=>d,default:()=>O,frontMatter:()=>h,gallery10Images:()=>y,gallery11Images:()=>P,gallery12Images:()=>x,gallery13Images:()=>L,gallery14Images:()=>X,gallery15Images:()=>k,gallery16Images:()=>B,gallery17Images:()=>U,gallery18Images:()=>G,gallery19Images:()=>T,gallery1Images:()=>_,gallery20Images:()=>z,gallery21Images:()=>q,gallery22Images:()=>I,gallery23Images:()=>M,gallery24Images:()=>A,gallery2Images:()=>u,gallery3Images:()=>m,gallery4Images:()=>j,gallery5Images:()=>w,gallery6Images:()=>f,gallery7Images:()=>v,gallery9Images:()=>b,metadata:()=>n,toc:()=>F});const n=JSON.parse('{"id":"GijsGroteZolderverbouwing/index","title":"Gijs\' great attic makeover","description":"The house Gijs bought in 2019 was already a bit older. Over the years, the roof had started to bend slightly, and because of this the roof window no longer sealed properly. While a drafty roof window is not a disaster in itself (a house still needs ventilation), it does cause a lot of heat loss. With rising energy prices, there was only one option left: a complete attic makeover!","source":"@site/i18n/en/docusaurus-plugin-content-docs/current/3_GijsGroteZolderverbouwing/index.mdx","sourceDirName":"3_GijsGroteZolderverbouwing","slug":"/GijsGroteZolderverbouwing/","permalink":"/en/GijsGroteZolderverbouwing/","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{}}');var t=i(4848),s=i(8453),r=i(5643);i(6540);function o(e,a){if(!e)return"";if((i=e)&&(i.startsWith("http://")||i.startsWith("https://"))||e.startsWith("/"))return e;var i;const n=function(e){return e?e.endsWith("/")?e.slice(0,-1):e:""}(a),t=function(e){return e?e.startsWith("/")?e.slice(1):e:""}(e);return n?n+"/"+t:t}function l(e){const a=e||{},i=a.images||[],n=a.basePath||"",s=a.originalBaseUrl||"",l=a.thumbnailBaseUrl||"",h=void 0===a.lazyLoad||a.lazyLoad,d=function(e,a){const i=e||[],n=a||{},t=n.basePath||"",s=n.originalBaseUrl||"",r=n.thumbnailBaseUrl||"";return i.map(e=>({original:o(e,s||t),thumbnail:o(e,r||s||t)}))}(i,{basePath:n,originalBaseUrl:s,thumbnailBaseUrl:l});return d.length?(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(r.A,{items:d,lazyLoad:h}),(0,t.jsx)("br",{})]}):null}const h={},d="Gijs' great attic makeover",g={},c="https://res.cloudinary.com/kingtech/image/upload",p="https://res.cloudinary.com/kingtech/image/upload/c_fill,g_auto,w_250,h_150,q_auto,f_auto",_=["v1772892389/PXL_20251026_093655720_cxjs4z.jpg","v1772892390/PXL_20251026_093659268_ac2gij.jpg","v1772892389/PXL_20251026_093502451.MP_vh4ay2.jpg","v1772892390/PXL_20251026_155826107_ix2mnm.jpg","v1772892391/PXL_20251026_175202142_pq9st9.jpg","v1772892393/PXL_20251027_093954599.MP_ujqrb4.jpg","v1772892392/PXL_20251026_175207682_nernkx.jpg"],u=["v1772895879/PXL_20251027_092404764_ynu2q8.jpg","v1772895880/PXL_20251027_092340747_ss0akp.jpg","v1772895881/PXL_20251027_092343176.MP_qmne3g.jpg"],m=["v1772895961/PXL_20251028_131426127_scgq6e.jpg","v1772895971/PXL_20251104_101243954.MP_ym5wje.jpg","v1772895982/PXL_20251104_113914185_tfrrsy.jpg"],j=["v1772896038/PXL_20251029_122500179_xcw5tq.jpg","v1772896046/PXL_20251029_133700790_fbrhht.jpg","v1772896054/PXL_20251031_145045332_hoeajs.jpg"],w=["v1772896101/PXL_20251101_105705034.MP_yizefm.jpg","v1772896113/PXL_20251101_180825018_ymaqsl.jpg","v1772896121/PXL_20251102_150245951_uswwt2.jpg","v1772896128/PXL_20251102_152641940_npyfwf.jpg","v1772896136/PXL_20251102_155510117.MP_fztkuw.jpg"],f=["v1772896204/PXL_20251103_072900091.MP_sw7f2g.jpg","v1772896212/PXL_20251103_075837450_mx09le.jpg","v1772896219/PXL_20251103_091931813_dwuhiy.jpg","v1772896226/PXL_20251103_092714477_pcmsfl.jpg","v1772896233/PXL_20251103_093755808_tpeknx.jpg","v1772896241/PXL_20251103_105233875.MP_eplygb.jpg","v1772896249/PXL_20251103_105406213.MP_knggxb.jpg","v1772896257/PXL_20251103_111238929.MP_jv5bkt.jpg","v1772896267/PXL_20251103_161528024_vpgk7r.jpg"],v=["v1772896387/PXL_20251104_132153385_w14qwo.jpg","v1772896394/PXL_20251104_152112564_w4671y.jpg","v1772896433/PXL_20251106_081815234_qcdebc.jpg","v1772896439/PXL_20251106_114227202_pi9qzx.jpg","v1772896447/PXL_20251106_183711436.MP_cuxxqx.jpg","v1772896454/PXL_20251107_145142610_ixvsz6.jpg"],b=["v1773345382/PXL_20251109_161224116_ra6rtu.jpg","v1772896511/PXL_20251107_101055933_v4nwvt.jpg","v1772896519/PXL_20251107_160456716_acszmb.jpg"],y=["v1772896580/PXL_20251105_073933446.MP_lsmvur.jpg","v1772896588/PXL_20251105_074051620.MP_wxbybb.jpg","v1772896598/PXL_20251105_074055683.MP_jmgne9.jpg","v1772896608/PXL_20251105_074221593.MP_lxitfk.jpg","v1772896617/PXL_20251105_074223077_vescx9.jpg","v1772896627/PXL_20251105_094923848_yaqdnm.jpg"],P=["v1772896703/PXL_20251109_145405056.MP_jmw9pb.jpg","v1772896713/PXL_20251109_145411349_m5jgsu.jpg","v1772896723/PXL_20251109_145446748_pd7nvv.jpg","v1772896760/PXL_20251109_152854607_jlqw0o.jpg","v1773585612/gijs-on-roof_ucy8fp.jpg"],x=["v1772896844/PXL_20251116_143822558.MP_urknpq.jpg","v1772896853/PXL_20251116_143838044_x9vz0a.jpg","v1772896860/PXL_20251116_143842455_w3nx6a.jpg","v1772896867/PXL_20251118_140907541_qjsyki.jpg","v1772896874/PXL_20251122_171121812_mwxvjf.jpg","v1772896527/PXL_20251109_093431360_onfqcr.jpg","v1772896880/PXL_20251122_171137950_d54ftn.jpg"],L=["v1772896965/PXL_20251123_091536120_ni9pza.jpg","v1772896973/PXL_20251125_152241462_sljy50.jpg","v1772896982/PXL_20251130_185733165_y7qx1n.jpg","v1772896993/PXL_20251130_185741295_dfvrea.jpg","v1772897003/PXL_20251130_185754660_ti0yac.jpg","v1772897012/PXL_20251130_185802553_yypzy0.jpg"],X=["v1773341189/PXL_20251202_145411662_rnbxf0.jpg","v1773341206/PXL_20251202_145420459_fp85wj.jpg","v1773341222/PXL_20251202_145430834_aiguan.jpg","v1773341243/PXL_20251202_145440549.MP_hszpu4.jpg"],k=["v1773341376/PXL_20251202_145642840_vbg1lf.jpg","v1773341402/PXL_20251202_145711984_sifwe4.jpg"],B=["v1773341552/PXL_20251226_090420354_jeow8n.jpg","v1773341581/PXL_20251226_090550020.MP_wmma3w.jpg"],U=["v1773342156/PXL_20251230_162740134_zpce5v.jpg","v1773342184/PXL_20251230_162747900_t6pdmd.jpg","v1773342204/PXL_20251231_093314614_qvxpoq.jpg"],G=["v1773342505/PXL_20260104_144842913_jcagmc.jpg","v1773342524/PXL_20260104_144902178_zebgoc.jpg","v1773342591/PXL_20260104_165740765_tw6p2q.jpg"],T=["v1773345456/PXL_20260113_153947893_vsebyu.jpg","v1773342641/PXL_20260104_165749586_sqschf.jpg","v1773342782/PXL_20260118_163708405_ckb1h0.jpg","v1773342802/PXL_20260118_163721765_lcjsak.jpg"],z=["v1773342886/PXL_20260120_162519048_lz5lqe.jpg","v1773342902/PXL_20260120_162531477_fgbcxx.jpg","v1773342926/PXL_20260127_160322674_kazn2x.jpg","v1773342943/PXL_20260127_160330138_wgxwmi.jpg","v1773342972/PXL_20260127_160342549_ropts2.jpg","v1773342989/PXL_20260201_132854893_y5nyph.jpg"],q=["v1773343008/PXL_20260203_170743895_ds1wfg.jpg","v1773343200/PXL_20260210_110629383_cprxbr.jpg","v1773343216/PXL_20260210_130444644_e6gwhm.jpg","v1773343233/PXL_20260210_155957734_uymsb0.jpg"],I=["v1773343362/PXL_20260301_102706080.MP_ufpwoz.jpg","v1773343378/PXL_20260301_170457209_pzr7vg.jpg","v1773343391/PXL_20260301_170502139_pwbenk.jpg","v1773343407/PXL_20260303_113144962_pnydoi.jpg","v1773343423/PXL_20260303_113148690.MP_mpxpsf.jpg"],M=["v1773343664/PXL_20260303_133835538_qraqwe.jpg","v1773343689/PXL_20260303_133844383_mbzz5f.jpg","v1773343705/PXL_20260303_155916635_onz7y0.jpg","v1773343727/PXL_20260303_155924725_uh3qwh.jpg","v1773343743/PXL_20260303_155931865_yjknlt.jpg","v1773343766/PXL_20260303_155940168_nkdurv.jpg","v1773947878/PXL_2026-03-19_at_8.16.28_PM_z7ead6.jpg"],A=["v1774451044/PXL_20260324_160908849_usvxm0.jpg","v1774451045/PXL_20260324_160918625_wcjrak.jpg","v1774451045/PXL_20260324_110439846_g8rkvk.jpg","v1774451045/PXL_20260324_160923926_nkb1pp.jpg","v1774451044/PXL_20260324_160948521_fetg6z.jpg"],F=[];function W(e){const a={a:"a",h1:"h1",header:"header",img:"img",p:"p",...(0,s.R)(),...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(a.header,{children:(0,t.jsx)(a.h1,{id:"gijs-great-attic-makeover",children:"Gijs' great attic makeover"})}),"\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n","\n",(0,t.jsx)("p",{style:{textAlign:"center"},children:(0,t.jsx)("img",{src:"/img/ggzv-banner.png",alt:"GGZV",loading:"lazy"})}),"\n",(0,t.jsx)(a.p,{children:"The house Gijs bought in 2019 was already a bit older. Over the years, the roof had started to bend slightly, and because of this the roof window no longer sealed properly. While a drafty roof window is not a disaster in itself (a house still needs ventilation), it does cause a lot of heat loss. With rising energy prices, there was only one option left: a complete attic makeover!"}),"\n",(0,t.jsx)(a.p,{children:"After Gijs created his own place in the shed, it was time to create a place for his lovely wife. Up until now, the attic had mainly served as storage space and a laundry area, but in the future this space should become a true woman cave. First, the attic had to be cleared out."}),"\n",(0,t.jsx)(a.p,{children:(0,t.jsx)(a.img,{src:"https://res.cloudinary.com/kingtech/image/upload/v1773580363/zolder-pre-cleanup_xnn1dm.jpg",alt:"Cluttered attic"})}),"\n",(0,t.jsx)(a.p,{children:"After the attic was emptied, Gijs and his helpers carefully dismantled the existing interior."}),"\n",(0,t.jsx)(l,{images:_,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"One of the big questions was: how well is the roof insulated?"}),"\n",(0,t.jsx)(a.p,{children:"Because a large hole would eventually be cut into the roof, Gijs first drilled a small inspection hole in the ceiling to check the thickness of the existing insulation.\nUnfortunately, it turned out to be only a thin PUR board. In the 1980s, when the house was built, this was considered sufficient, but it is far below today\u2019s standards."}),"\n",(0,t.jsx)(l,{images:u,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"So, off to the hardware store. Gijs stocked up big: beams, drywall sheets, and of course lots of insulation.\nThe first task was building a stud wall at the back side of the attic. Because attic space is limited, he split the renovation into smaller jobs and many trips to the store."}),"\n",(0,t.jsx)(l,{images:m,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Because it was late autumn when Gijs started this attic makeover, and he wanted to keep windows closed as much as possible due to the cold, he had to minimize dust.\nGijs has a great miter saw, but the dust extractor connection was made specifically for Bosch Blue vacuum cleaners. Gijs already had a great K\xe4rcher vacuum with a more standard connector."}),"\n",(0,t.jsxs)(a.p,{children:["He could have solved this with duct tape, but Gijs is a modern man with a 3D printer. Being resourceful, he designed an adapter so standard vacuums can connect to Bosch Blue tools. The files are, of course, available ",(0,t.jsx)(a.a,{href:"https://www.thingiverse.com/thing:7315811",children:"for free online"}),"."]}),"\n",(0,t.jsx)(l,{images:j,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Then the real structural work began.\nGijs installed a stud wall in front of the rear attic wall. This allows better insulation and cleaner routing of cables and pipes inside the wall. Since this wall borders the neighbor\u2019s house (which also has a livable attic), he also hoped to reduce sound transfer in both directions."}),"\n",(0,t.jsx)(a.p,{children:"The plan is to mount a TV on the right side, so Gijs added an extra-wide shaft for hidden cabling. This keeps peripherals (consoles, receivers, etc.) neatly out of sight. A power outlet is also included so all TV cables can be concealed."}),"\n",(0,t.jsx)(a.p,{children:"Finally, a wide shaft was added for ventilation from the ground floor. For this he reused the old cooker hood duct. It has not been used for years, and because better insulation makes ventilation increasingly important, this was a practical reuse."}),"\n",(0,t.jsx)(l,{images:w,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Then came the big moment: the dormer was installed.\nGijs did not do this himself; building and installing a dormer is specialist work. From an insurance perspective, it is also wiser to hire a professional company."}),"\n",(0,t.jsx)(a.p,{children:"The dormer was prefabricated in a workshop and installed as one unit.\nFirst, a hole was cut in the roof, and all debris was loaded into big bags so a large crane could lift it down through the opening. Gijs made eager use of this by buying his own big bag and filling it with construction waste, saving a lot of heavy carrying."}),"\n",(0,t.jsx)(a.p,{children:"After all waste was removed, the crane lifted the dormer over the roof and secured it in its final position. It was then sealed water- and airtight with lead flashing and insulating foam."}),"\n",(0,t.jsx)(l,{images:f,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsxs)(a.p,{children:["After this exciting interruption, Gijs went straight back to work on the stud wall. He already gained experience with this in ",(0,t.jsxs)(a.a,{href:"/GijsGroteGarageverbouwing/",children:["Gijs Grote Garageverbouwing ",(0,t.jsx)("sup",{children:"\xa9"})]}),"."]}),"\n",(0,t.jsx)(a.p,{children:"First he built a frame and filled it with glass wool insulation. OSB boards were screwed onto the frame to add rigidity. This makes the wall more impact-resistant and makes it easier to mount shelves or paintings later.\nDrywall sheets were then installed for a clean finish. To hide seams neatly, Gijs chose boards with recessed edges so joint compound could be applied and smoothed flush."}),"\n",(0,t.jsx)(l,{images:v,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Then it was time to insulate the ceiling. For this, Gijs used thick PUR boards with an R-value of 4.5.\nCombined with the existing insulation, this brings the roof insulation in line with current new-build standards. Gijs held a piece of old insulation next to the new boards to clearly show the difference."}),"\n",(0,t.jsx)(a.p,{children:"Because PUR boards are very thick and screws have little to no grip in this material, Gijs chose construction adhesive. The existing ceiling first had to be thoroughly degreased.\nThen the boards were cut to size and construction adhesive (a PUR-like foam) was sprayed onto each board. The foam had to rest for 5 minutes before pressing the board against the ceiling.\nEach board then had to be held in place for over a minute before moving on."}),"\n",(0,t.jsx)(l,{images:b,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"As you can imagine, insulating an attic is a lot of work.\nFortunately, Gijs managed to recruit helpers to cut insulation boards to size. That way, he can also teach the next generation practical DIY skills."}),"\n",(0,t.jsx)(l,{images:y,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Unfortunately, while insulating, Gijs discovered signs of an old leak.\nThis turned out to be caused by cracks in aging lead flashing and roof boarding near a level change in the house."}),"\n",(0,t.jsx)(a.p,{children:"For the new roof boarding, Gijs chose Keralit instead of wood. These synthetic boards are nearly indistinguishable from real wood at normal viewing distance, but unlike wood they require little to no maintenance."}),"\n",(0,t.jsx)(a.p,{children:"This did mean renovation work had to pause until the leak was fixed.\nLuckily, Gijs found skilled local tradesmen who could come quickly. He still had to remove the solar panels temporarily himself so they could do their work. That meant climbing onto the roof, which he definitely does not enjoy."}),"\n",(0,t.jsx)(l,{images:P,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Although he could not continue in the leak corner, he could continue on the rest of the roof.\nSo he kept working tirelessly, installing new insulation boards against the ceiling and covering them with drywall for a clean finish.\nThese drywall boards were also fixed with construction adhesive, because screws cannot grip the insulation behind them."}),"\n",(0,t.jsx)(l,{images:x,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"After finishing the ceiling with drywall, the attic immediately started to feel much more complete.\nGluing the insulation and drywall allowed Gijs to keep the construction compact, so the original beams remain visible, which was an important wish from his wife."}),"\n",(0,t.jsx)(l,{images:L,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"To turn the individual drywall boards into one clean whole, Gijs filled all seams with joint compound.\nJust like the boards on his stud wall, these board edges are slightly recessed so they can be merged into one smooth surface.\nIt looks messy at first, but once sanded and painted, the separate boards are barely distinguishable."}),"\n",(0,t.jsx)(l,{images:X,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Using a thermal camera, Gijs can check whether the Knauf compound has dried well and whether any spots are still poorly insulated.\nUntil everything is neatly caulked, a visible gap remains around the boards."}),"\n",(0,t.jsx)(l,{images:k,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"After filling and sanding, it was time for a first coat of primer.\nThis prevents the vulnerable gypsum surface from being damaged during further work. Gypsum itself is very delicate; even a soft brush can leave grooves.\nPrimer binds by penetrating deep into the material and provides a first protective layer."}),"\n",(0,t.jsx)(l,{images:U,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"For a clean finish at the roof ridge, it was decided to lower it slightly.\nBecause this is an older house, walls and beams are not perfectly straight. The lowered ceiling helps conceal that."}),"\n",(0,t.jsx)(a.p,{children:"As an additional benefit, Gijs can install recessed spotlights for evening lighting.\nBecause the final room layout was still unknown, a traditional hanging lamp could limit options. Spotlights are a great flexible solution."}),"\n",(0,t.jsx)(l,{images:G,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsxs)(a.p,{children:["Then it was time for the other side of the attic.\nSo far, the work was fairly straightforward. But this side includes the staircase, central heating boiler, solar inverter, washing machine and dryer. ",(0,t.jsx)("br",{}),"\nWhere many homes keep a 1\u20132 meter strip open and place a wall with a door, Gijs decided to maximize every bit of space."]}),"\n",(0,t.jsx)(a.p,{children:"To finish around the stair opening, he wanted to build a surrounding wall.\nThis wall would continue on both sides to create a space for the boiler and a storage room.\nThe washing machine sits in a utility tray with drain (in case of leakage), and Gijs wanted to keep that functional.\nUnfortunately, not everything is in one straight line, so some creative carpentry was required.\nBut first: new materials."}),"\n",(0,t.jsx)(l,{images:T,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Unlike the wall on the other side of the attic, this one is freestanding, so it needed finishing on both sides.\nAgain, Gijs added a wooden board behind the drywall for extra strength.\nA layer of glass wool was placed between the studs.\nEven though this wall does not require thermal insulation, it helps acoustics. The wall transmits less sound, which is immediately noticeable when you knock on it."}),"\n",(0,t.jsx)(a.p,{children:"The ceiling in the stair opening was also finished neatly.\nThis not only looks cleaner, but also allows routing pipes and cables from one side of the stair opening to the other."}),"\n",(0,t.jsx)(l,{images:z,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Of course, this wall was also finished with drywall for a clean look.\nGijs left openings for a door to the stair opening, the storage room next to the stairs, and an additional storage area above the stair opening.\nHe also plans to place the dryer in a niche, which is the opening you see on the left.\nBecause placing the dryer would otherwise leave unused space next to it, he also left an opening for a cabinet. This way every centimeter is used."}),"\n",(0,t.jsx)(l,{images:q,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"The stair opening itself was also finished neatly.\nTo cover the bare concrete wall, Gijs mounted drywall panels using construction adhesive.\nProps hold the panels against the concrete while the adhesive cures, allowing him to cut the next panel to size in the meantime."}),"\n",(0,t.jsx)(l,{images:I,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"Drywall is relatively fragile, so to protect corners from impact, metal corner profiles were installed everywhere.\nThis prevents damage when someone bumps into wall corners or openings."}),"\n",(0,t.jsx)(a.p,{children:"These boards were then skimmed again with Knauf compound.\nIt may look rough at first, but Gijs prefers applying a wider layer before sanding it smooth. This delivers a very clean end result."}),"\n",(0,t.jsx)(l,{images:M,originalBaseUrl:c,thumbnailBaseUrl:p}),"\n",(0,t.jsx)(a.p,{children:"After sanding and priming, this phase of the renovation is complete as well.\nBefore Gijs starts the next phase, it is time to tidy up the attic. For the next phase he needs to be able to move around freely, and a tidy workspace is essential for that.\nBesides: an orderly workspace makes for an orderly mind."}),"\n",(0,t.jsx)(l,{images:A,originalBaseUrl:c,thumbnailBaseUrl:p})]})}function O(e={}){const{wrapper:a}={...(0,s.R)(),...e.components};return a?(0,t.jsx)(a,{...e,children:(0,t.jsx)(W,{...e})}):W(e)}}}]);